const client = $input.first().json;

const colors = Array.isArray(client.brand_colors)
  ? client.brand_colors.slice(0, 10).join(', ')
  : (client.brand_colors || 'brand-appropriate colors');

const services = Array.isArray(client.services)
  ? client.services.join(', ')
  : (client.services || '');

const locationLine = client.location ? `Location: ${client.location}` : '';

const systemPrompt = `You are an expert viral social media content creator. Generate highly engaging, platform-optimised posts. Respond with valid JSON only — no markdown, no code blocks.`;

const userPrompt = `Create 5 viral social media posts for this brand:

Brand: ${client.name}
Industry: ${client.industry || 'General'}
Tone: ${client.tone_of_voice || 'Professional'}
Services: ${services}
Audience: ${client.target_audience || 'General public'}
${locationLine}
Image Style: ${client.image_style || 'Photorealistic professional photography'}
Brand Colors: ${colors}

Return ONLY a JSON object with this structure:
{
  "posts": [
    {
      "hook": "viral opening line under 10 words",
      "caption": "engaging caption 150-300 chars",
      "call_to_action": "clear compelling CTA",
      "hashtags": ["tag1", "tag2", "tag3", "tag4", "tag5"],
      "image_prompt": "detailed prompt: subject, environment, lighting, camera angle, photorealistic, brand colors: ${colors}",
      "emotional_trigger": "fear|joy|curiosity|urgency|trust",
      "content_type": "educational|promotional|engagement|storytelling"
    }
  ]
}`;

return [{ json: { client_id: client.id, client, systemPrompt, userPrompt } }];

const response = $input.first().json;
const clientId = $('Build Prompt').first().json.client_id;

let content;
try {
  content = response.choices[0].message.content;
} catch(e) {
  throw new Error('Invalid OpenRouter response: ' + JSON.stringify(response).substring(0, 300));
}

let parsed;
try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Failed to parse JSON from Claude: ' + content.substring(0, 500));
}

const posts = parsed.posts || [];
if (!posts.length) throw new Error('No posts returned from Claude');

return [{ json: { client_id: clientId, posts } }];

const { client_id, posts } = $input.first().json;
const apiKey = 'PASTE_YOUR_OPENROUTER_KEY_HERE';
const imageModel = 'google/gemini-2.5-flash-image';
const PLACEHOLDER = 'https://placehold.co/1024x1024/1a1a2e/ffffff.png';

async function generateImage(prompt) {
  try {
    const res = await fetch('https://openrouter.ai/api/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
        'HTTP-Referer': 'https://joat.studio',
        'X-Title': 'AI Content Engine'
      },
      body: JSON.stringify({
        model: imageModel,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (!res.ok) return null;
    const data = await res.json();
    const msg = data.choices?.[0]?.message;
    if (!msg) return null;
    if (msg.images?.[0]?.image_url?.url) return msg.images[0].image_url.url;
    if (Array.isArray(msg.content)) {
      for (const block of msg.content) {
        if (block.type === 'image_url' && block.image_url?.url) return block.image_url.url;
      }
    }
    return null;
  } catch(e) {
    console.log('Image gen failed:', e.message);
    return null;
  }
}

const processed = [];
for (const post of posts) {
  const imageUrl = await generateImage(post.image_prompt);
  processed.push({ ...post, image_url: imageUrl || PLACEHOLDER });
}

return [{ json: { client_id, posts: processed } }];
